CREATE TABLE regulations_to_carveout
(
	id serial,
	regulation_id integer DEFAULT NULL,
	industry_id integer NOT NULL,

	CONSTRAINT pk_regulations_to_carveout PRIMARY KEY (id)
	, CONSTRAINT fk_regulations_to_carveout_to_industry FOREIGN KEY (industry_id) REFERENCES industries (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_regulations_to_carveout_to_regulations FOREIGN KEY (regulation_id) REFERENCES regulations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_regulations_to_carveout_to_industry ON regulations_to_carveout (industry_id);
CREATE INDEX i_regulations_to_carveout_regulation ON regulations_to_carveout (regulation_id);
